//! Amplituhedron cache — a disk-backed "compute once, replay forever" cache that
//! sits behind prompt execution, modeled on the skymesh Protocol69 **FOIL** cache
//! (`apps/skymesh/src/durables/MeshCacheNodeDO.ts`). FOIL keys an answer by an
//! exact fingerprint of the query and replays it forever; this is the same idea
//! lowered into moonshine.
//!
//! Two properties make the on-disk store mandatory rather than a nicety:
//!   1. moonshine runs as a *fresh process per `-c` invocation* (the browser
//!      agent spawns one per step), so an in-memory map would never survive to
//!      the next call. The cache has to be on disk to help at all.
//!   2. A hit must be *hella fast*: the hot path is a single hash-keyed file read
//!      + JSON parse (sub-millisecond) with NO tokenize, NO decode loop, NO
//!        network. The optional mycelial (mesh-shared) layer only ever runs on a
//!        miss, so it can never slow a hit.
//!
//! Keying mirrors FOIL's exact-match discipline: normalize the prompt (collapse
//! whitespace, lowercase), hash with FNV-1a/64, and store the normalized prompt
//! inside the entry so a hash collision is caught on read and treated as a miss.

use std::path::PathBuf;
use std::time::{SystemTime, UNIX_EPOCH};

/// One cached generation: enough to reconstruct a `MeshGeneration` plus a text
/// answer (for the lighter text-level callers) and provenance, à la FOIL's
/// `Protocol69FilledCacheEntry`.
#[derive(serde::Serialize, serde::Deserialize, Clone)]
pub struct CachedGeneration {
    /// Normalized prompt — the collision guard (verified equal on read).
    pub prompt_norm: String,
    pub prompt_tokens: Vec<u32>,
    pub generated_tokens: Vec<u32>,
    /// Decoded answer text, when the caller has it (text-level cache path).
    #[serde(default)]
    pub answer_text: String,
    pub provenance: String,
    pub filled_at: u64,
}

const FNV_OFFSET: u64 = 0xcbf2_9ce4_8422_2325;
const FNV_PRIME: u64 = 0x0000_0100_0000_01b3;

fn fnv1a64(bytes: &[u8]) -> u64 {
    let mut h = FNV_OFFSET;
    for &b in bytes {
        h ^= b as u64;
        h = h.wrapping_mul(FNV_PRIME);
    }
    h
}

/// Collapse runs of whitespace to single spaces, trim, lowercase.
fn normalize(s: &str) -> String {
    s.split_whitespace().collect::<Vec<_>>().join(" ").to_lowercase()
}

/// The 16-hex cache key for a normalized prompt.
pub fn key(prompt_norm: &str) -> String {
    format!("{:016x}", fnv1a64(prompt_norm.as_bytes()))
}

/// Cache is on unless `MOONSHINE_NO_CACHE` is set.
pub fn enabled() -> bool {
    std::env::var("MOONSHINE_NO_CACHE").is_err()
}

/// `MOONSHINE_CACHE_DIR`, else `$XDG_CACHE_HOME/moonshine/amplituhedron`, else
/// `$HOME/.cache/...`, else a temp dir.
fn cache_dir() -> PathBuf {
    if let Ok(d) = std::env::var("MOONSHINE_CACHE_DIR") {
        return PathBuf::from(d);
    }
    let base = std::env::var("XDG_CACHE_HOME")
        .map(PathBuf::from)
        .or_else(|_| std::env::var("HOME").map(|h| PathBuf::from(h).join(".cache")))
        .unwrap_or_else(|_| std::env::temp_dir());
    base.join("moonshine").join("amplituhedron")
}

fn now_secs() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_secs())
        .unwrap_or(0)
}

/// HOT PATH. A single keyed file read + parse. Returns the cached generation iff
/// the stored normalized prompt matches exactly (collision guard).
pub fn lookup(prompt: &str) -> Option<CachedGeneration> {
    if !enabled() {
        return None;
    }
    let norm = normalize(prompt);
    let path = cache_dir().join(format!("{}.json", key(&norm)));
    let data = std::fs::read(&path).ok()?;
    let entry: CachedGeneration = serde_json::from_slice(&data).ok()?;
    if entry.prompt_norm != norm {
        return None; // hash collision — treat as miss
    }
    Some(entry)
}

/// Seed the cache (compute once, replay forever). Empty generations are not
/// cached. Best-effort + atomic-ish (write temp, rename); failures are silent so
/// caching never breaks generation.
pub fn store(
    prompt: &str,
    prompt_tokens: &[u32],
    generated_tokens: &[u32],
    answer_text: &str,
    provenance: &str,
) {
    // Text-only callers (HTTP-based chat completions, e.g. the agent tool
    // loop) have no raw token arrays at all — only require *something* worth
    // replaying (tokens OR decoded text), not tokens specifically.
    if !enabled() || (generated_tokens.is_empty() && answer_text.trim().is_empty()) {
        return;
    }
    let norm = normalize(prompt);
    let dir = cache_dir();
    if std::fs::create_dir_all(&dir).is_err() {
        return;
    }
    let entry = CachedGeneration {
        prompt_norm: norm.clone(),
        prompt_tokens: prompt_tokens.to_vec(),
        generated_tokens: generated_tokens.to_vec(),
        answer_text: answer_text.to_string(),
        provenance: provenance.to_string(),
        filled_at: now_secs(),
    };
    if let Ok(json) = serde_json::to_vec(&entry) {
        let k = key(&norm);
        let final_path = dir.join(format!("{k}.json"));
        let tmp_path = dir.join(format!("{k}.{}.tmp", std::process::id()));
        if std::fs::write(&tmp_path, &json).is_ok() {
            let _ = std::fs::rename(&tmp_path, &final_path);
        }
    }
}

// ── mycelial layer: a distributed, opt-in spread of the cache across nodes ────
//
// Like fungal mycelium, an answer computed by ONE node propagates to the whole
// network: on a local miss we consult the mesh, and after we compute we seed the
// mesh so every other node can replay it. Modeled on FOIL ("compute once, replay
// forever") but content-addressed by moonshine's own FNV key, so it needs no
// tokenize-before-lookup — a plain key→`CachedGeneration` store over HTTP.
//
// Strictly OPT-IN via `MOONSHINE_MYCELIAL_URL` (off by default → zero network on
// the hot path), best-effort (any error falls through to local compute), and
// only ever exercised on a LOCAL miss, so it can never slow or break a hit.
//
// Wire protocol (operator points it at any compatible KV / a skymesh route):
//   GET  {url}/amplituhedron/{key}        -> 200 CachedGeneration JSON | 404
//   PUT  {url}/amplituhedron/{key}        <- CachedGeneration JSON

/// The sovereign skymesh mesh that backs the mycelial layer by default.
pub const DEFAULT_MYCELIAL_URL: &str = "https://skymesh.forkjoin.ai";

/// The mycelial mesh base URL. **Default-ON**: with nothing configured it points
/// at the sovereign skymesh mesh, so every node's cached answers spread across
/// the whole fleet automatically — that is the entire point of the mycelial
/// layer. The local L1 cache is still consulted first (station-free, instant), so
/// a hit never touches the network; the mesh is reached only on a local miss.
///
/// Opt OUT with `MOONSHINE_NO_MYCELIAL=1` (or `MOONSHINE_MYCELIAL_URL=off`), or
/// point it somewhere else with `MOONSHINE_MYCELIAL_URL=<url>`. `MOONSHINE_NO_CACHE`
/// disables the whole cache, mycelial included.
pub fn mycelial_url() -> Option<String> {
    if !enabled() || std::env::var("MOONSHINE_NO_MYCELIAL").is_ok() {
        return None;
    }
    match std::env::var("MOONSHINE_MYCELIAL_URL") {
        Ok(raw) => {
            let u = raw.trim().trim_end_matches('/');
            if u.is_empty()
                || u.eq_ignore_ascii_case("off")
                || u.eq_ignore_ascii_case("none")
                || u.eq_ignore_ascii_case("disabled")
            {
                None
            } else {
                Some(u.to_string())
            }
        }
        Err(_) => Some(DEFAULT_MYCELIAL_URL.to_string()),
    }
}

fn mycelial_timeout() -> std::time::Duration {
    let secs = std::env::var("MOONSHINE_MYCELIAL_TIMEOUT_MS")
        .ok()
        .and_then(|v| v.trim().parse::<u64>().ok())
        .unwrap_or(1500);
    std::time::Duration::from_millis(secs)
}

/// Consult the mesh for a previously-computed answer (local miss only). On a hit,
/// the entry is also written to the local cache so subsequent calls are instant.
pub async fn mycelial_lookup(prompt: &str) -> Option<CachedGeneration> {
    let base = mycelial_url()?;
    let norm = normalize(prompt);
    let k = key(&norm);
    let client = reqwest::Client::builder()
        .timeout(mycelial_timeout())
        .build()
        .ok()?;
    let resp = client
        .get(format!("{base}/amplituhedron/{k}"))
        .send()
        .await
        .ok()?;
    if !resp.status().is_success() {
        return None;
    }
    let entry: CachedGeneration = resp.json().await.ok()?;
    if entry.prompt_norm != norm {
        return None;
    }
    // Warm the local cache from the mycelial hit.
    store(
        prompt,
        &entry.prompt_tokens,
        &entry.generated_tokens,
        &entry.answer_text,
        &entry.provenance,
    );
    Some(entry)
}

const DIRECT_CHAT_PREFIX: &str = "Answer the user directly and concisely.\nUser:";
const DIRECT_CHAT_SUFFIX: &str = "\nAnswer:";

fn extract_direct_user_prompt(prompt: &str) -> Option<String> {
    let rest = prompt.strip_prefix(DIRECT_CHAT_PREFIX)?;
    let user = rest.strip_suffix(DIRECT_CHAT_SUFFIX)?.trim();
    if user.is_empty() {
        None
    } else {
        Some(user.to_string())
    }
}

#[derive(serde::Deserialize)]
struct MycelialAskResponse {
    ok: Option<bool>,
    source: Option<String>,
    #[serde(default, rename = "answer")]
    answer_text: String,
    #[serde(default, rename = "answerTokens")]
    answer_tokens: Vec<u32>,
    #[serde(default, rename = "promptTokens")]
    prompt_tokens: Vec<u32>,
    provenance: Option<String>,
}

/// Ask skymesh's token-keyed Protocol69 FOIL cache using the raw user question
/// encoded by the Worker. This is cache-only: a miss must not start ambient
/// generation, because Moonshine is only trying to replay an existing fill before
/// it warms the local station.
async fn mycelial_ask_lookup(prompt: &str) -> Option<CachedGeneration> {
    let base = mycelial_url()?;
    let question = extract_direct_user_prompt(prompt)?;
    let client = reqwest::Client::builder()
        .timeout(mycelial_timeout())
        .build()
        .ok()?;
    let resp = client
        .post(format!("{base}/ask"))
        .json(&serde_json::json!({
            "question": question,
            "cacheOnly": true,
            "maxNewTokens": 1,
        }))
        .send()
        .await
        .ok()?;
    if !resp.status().is_success() {
        return None;
    }
    let ask: MycelialAskResponse = resp.json().await.ok()?;
    if ask.ok != Some(true) || ask.source.as_deref() != Some("cache") || ask.answer_text.is_empty() {
        return None;
    }
    let entry = CachedGeneration {
        prompt_norm: normalize(prompt),
        prompt_tokens: ask.prompt_tokens,
        generated_tokens: ask.answer_tokens,
        answer_text: ask.answer_text,
        provenance: ask
            .provenance
            .unwrap_or_else(|| "skymesh-protocol69-cache".to_string()),
        filled_at: now_secs(),
    };
    if !entry.generated_tokens.is_empty() {
        store(
            prompt,
            &entry.prompt_tokens,
            &entry.generated_tokens,
            &entry.answer_text,
            &entry.provenance,
        );
    }
    Some(entry)
}

/// Station-free TEXT lookup for the fastest callers: local first (sub-ms), then
/// the mycelial mesh (only if `MOONSHINE_MYCELIAL_URL` is set). Returns an entry
/// only when it carries decoded `answer_text`, so the caller can reply with zero
/// station contact. With mycelial off this is just the local read.
pub async fn lookup_text(prompt: &str) -> Option<CachedGeneration> {
    if let Some(hit) = lookup(prompt) {
        if !hit.answer_text.is_empty() {
            return Some(hit);
        }
    }
    if mycelial_url().is_some() {
        if let Some(hit) = mycelial_lookup(prompt).await {
            if !hit.answer_text.is_empty() {
                return Some(hit);
            }
        }
        if let Some(hit) = mycelial_ask_lookup(prompt).await {
            if !hit.answer_text.is_empty() {
                return Some(hit);
            }
        }
    }
    None
}

/// Seed the mesh after a local compute so the answer spreads to other nodes.
/// Best-effort; awaited (the surrounding miss already cost a full generation, so
/// a sub-second seed is negligible and a one-off process must not fire-and-forget).
pub async fn mycelial_seed(
    prompt: &str,
    prompt_tokens: &[u32],
    generated_tokens: &[u32],
    answer_text: &str,
    provenance: &str,
) {
    let Some(base) = mycelial_url() else { return };
    if generated_tokens.is_empty() && answer_text.trim().is_empty() {
        return;
    }
    let norm = normalize(prompt);
    let k = key(&norm);
    let entry = CachedGeneration {
        prompt_norm: norm,
        prompt_tokens: prompt_tokens.to_vec(),
        generated_tokens: generated_tokens.to_vec(),
        answer_text: answer_text.to_string(),
        provenance: provenance.to_string(),
        filled_at: now_secs(),
    };
    let Ok(client) = reqwest::Client::builder().timeout(mycelial_timeout()).build() else {
        return;
    };
    let _ = client
        .put(format!("{base}/amplituhedron/{k}"))
        .json(&entry)
        .send()
        .await;
}

#[cfg(test)]
mod tests {
    use super::*;

    // cargo test runs tests within a binary concurrently by default, but
    // every test below mutates the SAME process-wide MOONSHINE_CACHE_DIR env
    // var — without serializing, one test's set_var can leak into another's
    // still-running lookup/store calls (each uses a distinct directory, but
    // the env var pointing at "the current directory" is shared mutable
    // global state). Hold this lock for the duration of any such test.
    static ENV_TEST_LOCK: std::sync::Mutex<()> = std::sync::Mutex::new(());

    #[test]
    fn normalize_collapses_and_lowercases() {
        assert_eq!(normalize("  What   IS  2+2 "), "what is 2+2");
    }

    #[test]
    fn key_is_stable_and_normalization_insensitive() {
        assert_eq!(key(&normalize("hello  WORLD")), key(&normalize("hello world")));
        assert_ne!(key(&normalize("a")), key(&normalize("b")));
    }

    #[test]
    fn roundtrip_via_temp_dir() {
        let _guard = ENV_TEST_LOCK.lock().unwrap_or_else(|e| e.into_inner());
        let dir = std::env::temp_dir().join(format!("moonshine-cache-test-{}", std::process::id()));
        std::env::set_var("MOONSHINE_CACHE_DIR", &dir);
        let _ = std::fs::remove_dir_all(&dir);
        assert!(lookup("ping the void").is_none());
        store("ping the void", &[1, 2, 3], &[9, 8, 7], "the void", "test");
        let hit = lookup("  PING the   void ").expect("normalized hit");
        assert_eq!(hit.generated_tokens, vec![9, 8, 7]);
        assert_eq!(hit.answer_text, "the void");
        let _ = std::fs::remove_dir_all(&dir);
        std::env::remove_var("MOONSHINE_CACHE_DIR");
    }

    #[test]
    fn text_only_entry_with_empty_token_arrays_is_stored_and_retrievable() {
        // The agent tool loop (HTTP chat completions, no raw token access)
        // relies on this: store() must not require real token arrays as long
        // as there's decoded text worth replaying.
        let _guard = ENV_TEST_LOCK.lock().unwrap_or_else(|e| e.into_inner());
        let dir = std::env::temp_dir()
            .join(format!("moonshine-cache-test-textonly-{}", std::process::id()));
        std::env::set_var("MOONSHINE_CACHE_DIR", &dir);
        let _ = std::fs::remove_dir_all(&dir);
        assert!(lookup("hello").is_none());
        store("hello", &[], &[], "hi there", "moonshine-agent-tool-loop");
        let hit = lookup("hello").expect("text-only hit");
        assert!(hit.generated_tokens.is_empty());
        assert_eq!(hit.answer_text, "hi there");
        let _ = std::fs::remove_dir_all(&dir);
        std::env::remove_var("MOONSHINE_CACHE_DIR");
    }

    #[test]
    fn store_still_skips_a_genuinely_empty_result() {
        let _guard = ENV_TEST_LOCK.lock().unwrap_or_else(|e| e.into_inner());
        let dir = std::env::temp_dir()
            .join(format!("moonshine-cache-test-empty-{}", std::process::id()));
        std::env::set_var("MOONSHINE_CACHE_DIR", &dir);
        let _ = std::fs::remove_dir_all(&dir);
        store("nothing to see", &[], &[], "", "test");
        assert!(lookup("nothing to see").is_none());
        let _ = std::fs::remove_dir_all(&dir);
        std::env::remove_var("MOONSHINE_CACHE_DIR");
    }

    #[test]
    fn extracts_direct_user_prompt_for_skymesh_ask_lookup() {
        assert_eq!(
            extract_direct_user_prompt(
                "Answer the user directly and concisely.\nUser: capital of France?\nAnswer:"
            )
            .as_deref(),
            Some("capital of France?")
        );
        assert!(extract_direct_user_prompt("The capital of France is").is_none());
    }
}
